BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?parentName ?parentQN ?grandparentName ?grandparentQN WHERE {
  # The unnamed supplier requirement
  ?supplier vocab:NamedElement_qualifiedName ?sqn .
  FILTER(STR(?sqn) = "TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::OAD::System%20Definition::Observatory%20System%20Decomposition::Interfaces::")

  # Get its parent
  ?supplier vocab:Element_owner ?parent .
  OPTIONAL { ?parent vocab:NamedElement_name ?parentName }
  OPTIONAL { ?parent vocab:NamedElement_qualifiedName ?parentQN }

  # Get grandparent
  OPTIONAL {
    ?parent vocab:Element_owner ?grandparent .
    ?grandparent vocab:NamedElement_name ?grandparentName .
    ?grandparent vocab:NamedElement_qualifiedName ?grandparentQN .
  }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?parentName ?parentQN ?parentType WHERE {
  <TMT/tmt%20requirement/_12298_308f2c67-3ad6-4e24-92f6-cb2659c3918a> vocab:Element_owner ?parent .
  ?parent vocab:NamedElement_name ?parentName .
  OPTIONAL { ?parent vocab:NamedElement_qualifiedName ?parentQN }
  OPTIONAL { ?parent rdf:type ?parentType }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
