PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?parent ?parentQN ?parentType WHERE {
  <TMT/tmt%20requirement/_12298_308f2c67-3ad6-4e24-92f6-cb2659c3918a> vocab:Element_owner ?parent .
  OPTIONAL { ?parent vocab:NamedElement_qualifiedName ?parentQN }
  OPTIONAL { ?parent rdf:type ?parentType }
}
LIMIT 10
